contracts/ImpactBadge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title ImpactBadge
 * @notice ERC-721 NFT reward badges for PSL Pulse contributors
 * @dev Issued to top contributors per pillar
 */
contract ImpactBadge is ERC721, Ownable, AccessControl {
    
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    
    struct Badge {
        uint256 badgeId;
        uint256 matchId;
        uint8 pillarId;
        uint256 mintedAt;
        string metadataURI;
    }
    
    mapping(uint256 => Badge) public badges;
    uint256 private tokenIdCounter;
    
    event BadgeMinted(
        address indexed recipient,
        uint256 indexed tokenId,
        uint8 pillarId,
        uint256 matchId
    );
    
    event BadgeBurned(
        uint256 indexed tokenId
    );
    
    constructor() ERC721("PSL Impact Badge", "PSLBADGE") Ownable(msg.sender) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        tokenIdCounter = 0;
    }
    
    /**
     * @notice Mint a badge for a contributor
     * @param to Recipient address
     * @param pillarId Pillar ID (0-3)
     * @param matchId Match ID
     * @param uri Metadata URI (IPFS)
     */
    function mintBadge(
        address to,
        uint8 pillarId,
        uint256 matchId,
        string memory uri
    ) external onlyRole(MINTER_ROLE) {
        require(to != address(0), "Invalid recipient");
        require(pillarId < 4, "Invalid pillar");
        
        uint256 tokenId = tokenIdCounter++;
        
        badges[tokenId] = Badge({
            badgeId: tokenId,
            matchId: matchId,
            pillarId: pillarId,
            mintedAt: block.timestamp,
            metadataURI: uri
        });
        
        _safeMint(to, tokenId);
        
        emit BadgeMinted(to, tokenId, pillarId, matchId);
    }
    
    /**
     * @notice Get pillar for a badge
     * @param tokenId Token ID
     * @return Pillar ID
     */
    function pillarOf(uint256 tokenId) external view returns (uint8) {
        require(_ownerOf(tokenId) != address(0), "Badge does not exist");
        return badges[tokenId].pillarId;
    }
    
    /**
     * @notice Get badge metadata
     * @param tokenId Token ID
     * @return Badge struct
     */
    function getBadge(uint256 tokenId) external view returns (Badge memory) {
        require(_ownerOf(tokenId) != address(0), "Badge does not exist");
        return badges[tokenId];
    }
    
    /**
     * @notice Get token URI for metadata
     * @param tokenId Token ID
     * @return Metadata URI
     */
    function tokenURI(uint256 tokenId) 
        public 
        view 
        override 
        returns (string memory) 
    {
        require(_ownerOf(tokenId) != address(0), "Badge does not exist");
        return badges[tokenId].metadataURI;
    }
    
    /**
     * @notice Burn a badge
     * @param tokenId Token ID to burn
     */
    function burnBadge(uint256 tokenId) external {
        require(_ownerOf(tokenId) == msg.sender, "Not badge owner");
        _burn(tokenId);
        emit BadgeBurned(tokenId);
    }
    
    /**
     * @notice Grant minter role
     * @param account Address to grant role
     */
    function grantMinterRole(address account) external onlyRole(DEFAULT_ADMIN_ROLE) {
        grantRole(MINTER_ROLE, account);
    }
    
    // Required for AccessControl + ERC721
    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }
}

contracts/PSLImpactMarket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title PSLImpactMarket
 * @notice Main smart contract for PSL Pulse fan engagement platform
 * @dev Handles staking, tipping, and leaderboard management
 */
contract PSLImpactMarket is ReentrancyGuard, AccessControl, Ownable {
    
    // ─────────────── ROLES ───────────────
    bytes32 public constant ORACLE_ROLE = keccak256("ORACLE_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    
    // ─────────────── CONSTANTS ───────────────
    uint8 constant PILLAR_COUNT = 4;
    uint256 constant MIN_STAKE = 0.0001 ether; // Minimum stake in WIRE
    
    // ─────────────── STRUCTS ───────────────
    struct Match {
        uint256 matchId;
        uint8 team1;
        uint8 team2;
        uint256 startTime;
        uint256 endTime;
        string venue;
        bool active;
    }
    
    struct Pool {
        uint256 matchId;
        uint8 pillarId;
        uint256 totalStaked;
        uint256 stakeCount;
    }
    
    struct Contribution {
        uint256 totalContributed;
        uint256 stakeCount;
        uint256 tipCount;
    }
    
    // ─────────────── STATE ───────────────
    mapping(uint256 => Match) public matches;
    mapping(bytes32 => Pool) public pools;
    mapping(address => Contribution) public contributions;
    address[] public topContributors;
    
    uint256 public matchCounter;
    uint256 public totalStaked;
    uint256 public totalTipped;
    
    // ─────────────── EVENTS ───────────────
    event Staked(
        uint256 indexed matchId,
        uint8 indexed pillarId,
        address indexed staker,
        uint256 amount
    );
    
    event PlayerTipped(
        uint256 indexed matchId,
        bytes32 indexed playerId,
        address indexed tipper,
        uint256 amount
    );
    
    event InfinityWallUpdated(
        address indexed contributor,
        uint256 totalContributed,
        uint256 rank
    );
    
    event MatchCreated(
        uint256 indexed matchId,
        uint8 team1,
        uint8 team2,
        string venue
    );
    
    event MatchFinalized(
        uint256 indexed matchId
    );
    
    // ─────────────── CONSTRUCTOR ───────────────
    constructor() Ownable(msg.sender) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        matchCounter = 0;
    }
    
    // ─────────────── MATCH MANAGEMENT ───────────────
    /**
     * @notice Create a new match
     * @param team1 Team 1 ID
     * @param team2 Team 2 ID
     * @param startTime Unix timestamp for match start
     * @param venue Match venue name
     */
    function createMatch(
        uint8 team1,
        uint8 team2,
        uint256 startTime,
        string memory venue
    ) external onlyRole(ADMIN_ROLE) {
        require(team1 != team2, "Teams must be different");
        require(startTime > block.timestamp, "Start time must be in future");
        
        uint256 matchId = matchCounter++;
        
        matches[matchId] = Match({
            matchId: matchId,
            team1: team1,
            team2: team2,
            startTime: startTime,
            endTime: startTime + 4 hours,
            venue: venue,
            active: true
        });
        
        emit MatchCreated(matchId, team1, team2, venue);
    }
    
    /**
     * @notice Finalize a match (disable further staking)
     * @param matchId Match ID to finalize
     */
    function finalizeMatch(uint256 matchId) external onlyRole(ADMIN_ROLE) {
        require(matches[matchId].active, "Match already finalized");
        matches[matchId].active = false;
        emit MatchFinalized(matchId);
    }
    
    // ─────────────── STAKING ───────────────
    /**
     * @notice Stake WIRE into an impact pool
     * @param matchId Match ID
     * @param pillarId Pillar ID (0-3)
     */
    function stake(uint256 matchId, uint8 pillarId) 
        external 
        payable 
        nonReentrant 
    {
        require(msg.value >= MIN_STAKE, "Stake below minimum");
        require(pillarId < PILLAR_COUNT, "Invalid pillar");
        require(matches[matchId].active, "Match not active");
        require(msg.value > 0, "Cannot stake zero amount");
        
        // Update pool
        bytes32 poolKey = keccak256(abi.encodePacked(matchId, pillarId));
        pools[poolKey].matchId = matchId;
        pools[poolKey].pillarId = pillarId;
        pools[poolKey].totalStaked += msg.value;
        pools[poolKey].stakeCount++;
        
        // Update contributor
        contributions[msg.sender].totalContributed += msg.value;
        contributions[msg.sender].stakeCount++;
        
        totalStaked += msg.value;
        
        // Update leaderboard
        _updateInfinityWall(msg.sender);
        
        emit Staked(matchId, pillarId, msg.sender, msg.value);
    }
    
    // ─────────────── TIPPING ───────────────
    /**
     * @notice Tip a player directly
     * @param matchId Match ID
     * @param playerId Player ID (hashed)
     */
    function tipPlayer(uint256 matchId, bytes32 playerId) 
        external 
        payable 
        nonReentrant 
    {
        require(msg.value >= MIN_STAKE, "Tip below minimum");
        require(matches[matchId].active, "Match not active");
        require(msg.value > 0, "Cannot tip zero amount");
        
        // Update contributor
        contributions[msg.sender].totalContributed += msg.value;
        contributions[msg.sender].tipCount++;
        
        totalTipped += msg.value;
        
        // Update leaderboard
        _updateInfinityWall(msg.sender);
        
        emit PlayerTipped(matchId, playerId, msg.sender, msg.value);
    }
    
    // ─────────────── LEADERBOARD ───────────────
    /**
     * @notice Get top 10 contributors (Infinity Wall)
     * @return Array of top contributor addresses
     */
    function getInfinityWall() external view returns (address[] memory) {
        uint256 limit = topContributors.length > 10 ? 10 : topContributors.length;
        address[] memory wall = new address[](limit);
        
        for (uint256 i = 0; i < limit; i++) {
            wall[i] = topContributors[i];
        }
        
        return wall;
    }
    
    /**
     * @notice Get contributor stats
     * @param contributor Address of contributor
     * @return Contribution struct with stats
     */
    function getLeaderboard(address contributor) 
        external 
        view 
        returns (Contribution memory) 
    {
        return contributions[contributor];
    }
    
    /**
     * @notice Get pool data
     * @param matchId Match ID
     * @param pillarId Pillar ID
     * @return Pool struct with data
     */
    function getPool(uint256 matchId, uint8 pillarId) 
        external 
        view 
        returns (Pool memory)
    {
        bytes32 poolKey = keccak256(abi.encodePacked(matchId, pillarId));
        return pools[poolKey];
    }
    
    /**
     * @notice Get match data
     * @param matchId Match ID
     * @return Match struct with data
     */
    function getMatch(uint256 matchId) 
        external 
        view 
        returns (Match memory)
    {
        return matches[matchId];
    }
    
    // ─────────────── INTERNAL ───────────────
    /**
     * @notice Update Infinity Wall (sort top contributors)
     * @param contributor Address to rank
     */
    function _updateInfinityWall(address contributor) internal {
        bool found = false;
        
        // Check if contributor already in leaderboard
        for (uint256 i = 0; i < topContributors.length; i++) {
            if (topContributors[i] == contributor) {
                found = true;
                break;
            }
        }
        
        // Add new contributor if not found
        if (!found) {
            topContributors.push(contributor);
        }
        
        // Simple bubble sort (not optimized for production, but workable for demo)
        for (uint256 i = 0; i < topContributors.length; i++) {
            for (uint256 j = i + 1; j < topContributors.length; j++) {
                if (contributions[topContributors[j]].totalContributed > 
                    contributions[topContributors[i]].totalContributed) {
                    address temp = topContributors[i];
                    topContributors[i] = topContributors[j];
                    topContributors[j] = temp;
                }
            }
        }
        
        // Emit update
        uint256 rank = 1;
        for (uint256 i = 0; i < topContributors.length; i++) {
            if (topContributors[i] == contributor) {
                rank = i + 1;
                break;
            }
        }
        
        emit InfinityWallUpdated(contributor, contributions[contributor].totalContributed, rank);
    }
    
    // ─────────────── ADMIN FUNCTIONS ───────────────
    /**
     * @notice Grant oracle role to address
     * @param account Address to grant oracle role
     */
    function grantOracleRole(address account) external onlyRole(ADMIN_ROLE) {
        grantRole(ORACLE_ROLE, account);
    }
    
    /**
     * @notice Log impact event from oracle
     * @param matchId Match ID
     * @param eventData Event data (sixes, wickets, etc)
     */
    function logImpactEvent(uint256 matchId, string memory eventData) 
        external 
        onlyRole(ORACLE_ROLE) 
    {
        require(matches[matchId].active, "Match not active");
        // Event is just logged for off-chain processing
    }
    
    /**
     * @notice Withdraw contract balance (for payouts)
     * @param amount Amount to withdraw
     */
    function withdraw(uint256 amount) external onlyRole(ADMIN_ROLE) {
        require(address(this).balance >= amount, "Insufficient balance");
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "Withdrawal failed");
    }
    
    // ─────────────── RECEIVE ───────────────
    receive() external payable {}
}

contracts/PSLTicket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title PSLTicket
 * @notice ERC-721 NFT tickets for PSL Pulse matches
 * @dev Issues tiered match access tickets
 */
contract PSLTicket is ERC721, Ownable, AccessControl {
    
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    
    enum TicketTier {
        GENERAL,    // 0 - General admission
        PREMIUM,    // 1 - Premium seating
        VIP,        // 2 - VIP lounge
        HOSPITALITY // 3 - Hospitality suite
    }
    
    struct Ticket {
        uint256 ticketId;
        uint256 matchId;
        TicketTier tier;
        uint256 purchasePrice;
        uint256 mintedAt;
    }
    
    mapping(uint256 => Ticket) public tickets;
    mapping(uint256 => mapping(TicketTier => uint256)) public tierCapacity;
    mapping(uint256 => mapping(TicketTier => uint256)) public tierMinted;
    
    uint256 private tokenIdCounter;
    
    // Default tier prices (in WIRE)
    uint256 public constant GENERAL_PRICE = 0.05 ether;
    uint256 public constant PREMIUM_PRICE = 0.15 ether;
    uint256 public constant VIP_PRICE = 0.5 ether;
    uint256 public constant HOSPITALITY_PRICE = 1.0 ether;
    
    // Default capacity per match
    uint256 public constant GENERAL_CAPACITY = 1000;
    uint256 public constant PREMIUM_CAPACITY = 500;
    uint256 public constant VIP_CAPACITY = 100;
    uint256 public constant HOSPITALITY_CAPACITY = 50;
    
    event TicketMinted(
        address indexed buyer,
        uint256 indexed tokenId,
        uint256 matchId,
        TicketTier tier,
        uint256 price
    );
    
    event TicketBurned(
        uint256 indexed tokenId
    );
    
    constructor() ERC721("PSL Ticket", "PSLTICKET") Ownable(msg.sender) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        tokenIdCounter = 0;
    }
    
    /**
     * @notice Initialize match capacity
     * @param matchId Match ID
     */
    function initializeMatch(uint256 matchId) external onlyRole(DEFAULT_ADMIN_ROLE) {
        tierCapacity[matchId][TicketTier.GENERAL] = GENERAL_CAPACITY;
        tierCapacity[matchId][TicketTier.PREMIUM] = PREMIUM_CAPACITY;
        tierCapacity[matchId][TicketTier.VIP] = VIP_CAPACITY;
        tierCapacity[matchId][TicketTier.HOSPITALITY] = HOSPITALITY_CAPACITY;
    }
    
    /**
     * @notice Buy a ticket (mint)
     * @param matchId Match ID
     * @param tier Tier (0-3)
     */
    function buyTicket(uint256 matchId, TicketTier tier) 
        external 
        payable 
    {
        require(matchId > 0, "Invalid match ID");
        require(uint8(tier) < 4, "Invalid tier");
        
        // Check capacity
        uint256 capacity = tierCapacity[matchId][tier];
        uint256 minted = tierMinted[matchId][tier];
        require(minted < capacity, "Tier sold out");
        
        // Check payment
        uint256 requiredPrice = _getTierPrice(tier);
        require(msg.value >= requiredPrice, "Insufficient payment");
        
        // Mint ticket
        uint256 tokenId = tokenIdCounter++;
        
        tickets[tokenId] = Ticket({
            ticketId: tokenId,
            matchId: matchId,
            tier: tier,
            purchasePrice: msg.value,
            mintedAt: block.timestamp
        });
        
        tierMinted[matchId][tier]++;
        
        _safeMint(msg.sender, tokenId);
        
        emit TicketMinted(msg.sender, tokenId, matchId, tier, msg.value);
    }
    
    /**
     * @notice Get ticket tier
     * @param tokenId Token ID
     * @return Tier (0-3)
     */
    function tierOf(uint256 tokenId) external view returns (TicketTier) {
        require(_ownerOf(tokenId) != address(0), "Ticket does not exist");
        return tickets[tokenId].tier;
    }
    
    /**
     * @notice Get ticket data
     * @param tokenId Token ID
     * @return Ticket struct
     */
    function getTicket(uint256 tokenId) external view returns (Ticket memory) {
        require(_ownerOf(tokenId) != address(0), "Ticket does not exist");
        return tickets[tokenId];
    }
    
    /**
     * @notice Get tier price
     * @param tier Tier ID
     * @return Price in WIRE
     */
    function getTierPrice(TicketTier tier) external pure returns (uint256) {
        return _getTierPrice(tier);
    }
    
    /**
     * @notice Burn a ticket
     * @param tokenId Token ID to burn
     */
    function burnTicket(uint256 tokenId) external {
        require(_ownerOf(tokenId) == msg.sender, "Not ticket owner");
        _burn(tokenId);
        emit TicketBurned(tokenId);
    }
    
    /**
     * @notice Get available capacity for tier
     * @param matchId Match ID
     * @param tier Tier ID
     * @return Available capacity
     */
    function getAvailableCapacity(uint256 matchId, TicketTier tier) 
        external 
        view 
        returns (uint256) 
    {
        uint256 capacity = tierCapacity[matchId][tier];
        uint256 minted = tierMinted[matchId][tier];
        return capacity > minted ? capacity - minted : 0;
    }
    
    /**
     * @notice Withdraw contract balance
     * @param amount Amount to withdraw
     */
    function withdraw(uint256 amount) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(address(this).balance >= amount, "Insufficient balance");
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "Withdrawal failed");
    }
    
    // ─────────────── INTERNAL ───────────────
    function _getTierPrice(TicketTier tier) internal pure returns (uint256) {
        if (tier == TicketTier.GENERAL) return GENERAL_PRICE;
        if (tier == TicketTier.PREMIUM) return PREMIUM_PRICE;
        if (tier == TicketTier.VIP) return VIP_PRICE;
        if (tier == TicketTier.HOSPITALITY) return HOSPITALITY_PRICE;
        return 0;
    }
    
    // Required for AccessControl + ERC721
    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }
    
    // ─────────────── RECEIVE ───────────────
    receive() external payable {}
}

